class Data{
  constructor(x){
    this.x=x
    this.y=(1/3)*x**3
  }
    data() {
      return { 
        data:
          {x:this.x,y:this.y}
        }
      } 
}

function create(){
  let i
  let data= [] //Array
  let temp
  for(i=0;i<10;i += 0.1){
    temp=new Data(i)
    data.push(temp.data().data) //add the new value 
  }
  return data
}

var dataObj = [
  {
    id: "Sin curve",
    color: "hsl(253, 70%, 50%)",
    data: create(),
  },
];

export default dataObj
